SELECT rh.article_id as rh_id, a.title, a.summary, a.cover_image, a.user_id, a.author_name, u.avatar, rh.progress, rh.duration, rh.last_read_time, rh.scroll_position, DATE_FORMAT(rh.last_read_time, '%Y-%m-%d %H:%i') as read_time, DATE_FORMAT(rh.last_read_time, '%Y-%m-%d') as read_date FROM reading_history rh LEFT JOIN article a ON rh.article_id = a.id LEFT JOIN user u ON a.user_id = u.id WHERE rh.user_id = #{userId} AND rh.article_id IN
#{articleId}
AND rh.deleted = 0
